      growth_story: 'PM + ops manager roles growing. Customer success + revenue ops fastest-growing in SaaS. Mid-management squeezed in tech downturn (2022-2024 layoffs targeted middle management). HR + people ops shifting toward people analytics + DEI work + employer brand.',
      demographics: 'Mid + senior management ~60% men, with significant racial gap at executive levels (~10% of Fortune 500 CEOs are women, ~5% non-white). Entry business roles closer to parity. MBA programs increasingly diverse but pipeline gaps persist in private equity + venture + investment banking.',
      entry_picks: { hs: ['salesrep'], cert: [], associate: ['analystfin', 'salesrep'], bachelor: ['pm', 'salesrep', 'businessdev', 'customersuccess', 'hr', 'orgconsult', 'marketmgr'], graduate: ['pm', 'orgconsult', 'businessdev'], doctoral: [], professional: [] },
