      strong_fit_careers: ['lawyer', 'paralegal', 'psychologist', 'lpc', 'mhcounselor', 'professoll', 'profcollege', 'librarian', 'novelist', 'editor', 'translator', 'analystfin', 'datasci', 'swdev', 'pm', 'customersuccess'],
