        pbSection === 'mistakes' && h('section', { className: 'p-4 rounded-xl bg-rose-900/20 border border-rose-500/40 space-y-2' },
          h('h3', { className: 'text-sm font-black text-rose-200' }, '\u26a0 Personal brand mistakes'),
          h('ul', { className: 'space-y-2 text-xs text-slate-100 leading-relaxed' },
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Performative not authentic: '), 'Visible brand built on persona that isn\'t you eventually cracks. Long-term reputation = built on real character.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Controversy for engagement: '), 'Outrage gets clicks but corrodes reputation. Avoid hot takes on topics outside your expertise.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Constant self-promotion: '), 'Endless "look at me!" turns audience off. 80% giving + sharing others\' work, 20% own work is good ratio.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Generic + bland: '), 'Trying to please everyone = appealing to no one. Distinctive perspective + voice + niche outperforms.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Ignoring trolls vs feeding them: '), 'Most trolls want engagement. Don\'t. Block + move on. Don\'t spend energy on them.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Inconsistency: '), 'Posting daily for 2 weeks then silent for 6 months kills momentum. Sustainable rhythm > intense bursts.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Confusing audience: '), 'Posting about programming Monday, dating advice Tuesday, politics Wednesday confuses brand. Variety within focus = OK. Random = no.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Letting controversy define you: '), 'One viral controversy can dominate Google results for years. Defamation can be addressed legally; reputation rebuilt over time.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Tying brand to single company: '), 'When you leave, brand value drops. Personal brand should outlast employer.'),
            h('li', null, h('strong', { className: 'text-rose-300' }, 'Ignoring real work for brand: '), 'Best brand emerges from real work. People building brand instead of doing work eventually get exposed.')
          )
        )
