            h('li', null, h('strong', { className: 'text-emerald-300' }, 'Project management: '), 'Linear (small teams), Asana (cross-functional), Jira (eng), Monday, ClickUp. Match tool to team size + workflow.'),
            h('li', null, h('strong', { className: 'text-emerald-300' }, 'AI assistance: '), 'Email summarization + drafting, meeting transcription, calendar scheduling. Tools rapidly evolving 2024-2026.')
