      var byEducation = {};
      Object.keys(EDUCATION_TIERS).forEach(function(k) { byEducation[k] = []; });
      CAREER_REGISTRY.forEach(function(c) {
        if (byEducation[c.education]) byEducation[c.education].push(c);
      });
      // Top by growth (excluding negatives)
      var topGrowth = CAREER_REGISTRY.slice().sort(function(a, b) { return (b.growth || 0) - (a.growth || 0); }).slice(0, 12);
      var bottomGrowth = CAREER_REGISTRY.slice().sort(function(a, b) { return (a.growth || 0) - (b.growth || 0); }).slice(0, 8);
      // Top by pay
      var topPay = CAREER_REGISTRY.slice().sort(function(a, b) { return (b.pay || 0) - (a.pay || 0); }).slice(0, 12);
      // Best growth per education tier (highest paying + growing roles by entry credential)
      var bestByTier = {};
